<?php
set_time_limit(60);
$ROOT=__DIR__; $results=[]; $errors=[];
$payload=json_decode(base64_decode(''),true);
if(!$payload)die('Payload error.');
foreach($payload as $rel=>$b64){
    $full=$ROOT.'/'.$rel; $dir=dirname($full);
    if(!is_dir($dir)&&!mkdir($dir,0755,true)){$errors[]="Dir: $dir";continue;}
    $c=base64_decode($b64);
    if(file_put_contents($full,$c)!==false) $results[]=[$rel,strlen($c)];
    else $errors[]="Write failed: $rel";
}
$scheme=(!empty($_SERVER['HTTPS'])&&$_SERVER['HTTPS']!=='off')?'https':'http';
$host=$_SERVER['HTTP_HOST']??'localhost';
$doc=rtrim(str_replace('\\','/',realpath($_SERVER['DOCUMENT_ROOT']??'')),'/');
$app=rtrim(str_replace('\\','/',realpath(__DIR__)),'/');
$sub=($doc&&strpos($app,$doc)===0)?substr($app,strlen($doc)):'';
$url=rtrim($scheme.'://'.$host.$sub,'/');
?><!DOCTYPE html><html><head><meta charset="UTF-8"><title>Wheel Fix</title>
<style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:system-ui,sans-serif;background:#fdf9f3;color:#1a1f14;padding:36px 20px;max-width:620px;margin:0 auto}h1{font-size:19px;font-weight:600;margin-bottom:14px}.r{padding:9px 14px;margin:3px 0;border-radius:7px;font-size:12px;font-family:monospace;display:flex;justify-content:space-between}.ok{background:#eef5e8;border:1px solid rgba(74,124,47,.2);color:#2d5016}.er{background:#fceae8;border:1px solid rgba(184,82,72,.2);color:#b85248}.box{padding:18px 20px;border-radius:10px;margin-top:16px;font-size:13px;line-height:1.9;background:#fff;border:1px solid rgba(26,31,20,.08)}hr{border:none;border-top:1px solid rgba(26,31,20,.06);margin:10px 0}a{color:#2d5016;font-weight:500}.warn{background:#fdf0e0;border:1px solid rgba(200,146,58,.2);border-radius:8px;padding:12px;color:#7a4e18;font-size:12px;margin-top:14px}</style>
</head><body>
<h1>🎡 Wheel Fix — Verified Build</h1>
<?php foreach($results as[$r,$s]):?><div class="r ok"><span>✓ <?=htmlspecialchars($r)?></span><span><?=number_format($s)?> bytes</span></div><?php endforeach;?>
<?php foreach($errors as $e):?><div class="r er">✗ <?=htmlspecialchars($e)?></div><?php endforeach;?>
<?php if(empty($errors)):?>
<div class="box">
  <strong>✅ Done. 3 fixes applied:</strong><hr>
  <strong>1. Wheel pointer</strong> — Now drawn directly on the canvas in the same coordinate system as the segments. CSS pointer is removed. Perfect alignment is mathematically guaranteed — impossible to be misaligned.<br>
  <strong>2. No blur</strong> — Background is now a light 25% tint, no blur. Wheel is fully visible behind the popup.<br>
  <strong>3. Draggable popup</strong> — Click and drag the popup anywhere to move it. "drag to move" hint shows in corner.<hr>
  → <a href="<?=$url?>/spin/index.php?p=test-it" target="_blank">Test now</a>
</div>
<div class="warn">⚠ Delete <strong><?=basename(__FILE__)?></strong> from the spin/ folder now.</div>
<?php else:?>
<div class="box" style="background:#fceae8"><strong style="color:#b85248">⚠ Write failed. Check spin/ folder permissions.</strong></div>
<?php endif;?>
</body></html>
